import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen } from '@testing-library/react'
import { MantineProvider } from '@mantine/core'
import { InstitutionDetail } from './InstitutionDetail'
import type { SearchInstitution } from './types'

// Mock useQuery for SimilarInstitutions child component
const { mockUseQuery } = vi.hoisted(() => ({ mockUseQuery: vi.fn() }))
vi.mock('urql', () => ({ useQuery: mockUseQuery }))

// Mock useMediaQuery to return false (desktop) by default
vi.mock('@mantine/hooks', async () => {
  const actual = await vi.importActual<typeof import('@mantine/hooks')>('@mantine/hooks')
  return { ...actual, useMediaQuery: () => false }
})

const MOCK_INSTITUTION: SearchInstitution = {
  unitID: '166683',
  name: 'MIT',
  city: 'Cambridge',
  state: 'MA',
  latitude: 42.36,
  longitude: -71.09,
  academics: {
    institutionType: '2',
    highestDegree: '5',
    enrollment: 11574,
    gradEnrollment: 6990,
    studentFacultyRatio: 3,
    fullTimeFacultyRate: 0.92,
    gender: 'coed',
    onlineOnly: false,
    carnegieBasic: 15,
    carnegieSizeSetting: '17',
  },
  cost: {
    tuitionInState: 57590,
    tuitionOutOfState: 57590,
    avgNetPrice: 21642,
    roomAndBoard: 17810,
    avgNetPriceLowIncome: 4800,
    pellGrantRate: 0.18,
    federalLoanRate: 0.15,
    endowment: 27400000000,
  },
  outcomes: {
    admissionRate: 0.04,
    graduationRate: 0.94,
    retentionRate: 0.99,
    transferRate: 0.01,
  },
  rankings: {
    usNewsNational: 1,
    usNewsLiberalArts: null,
    forbes: 3,
    washingtonMonthlyNational: 5,
    washingtonMonthlyLiberalArts: null,
    niche: 2,
    moneyScore: 4.5,
  },
  admissions: {
    applicationPlatforms: ['Common App', 'Coalition'],
    satMath25: 780,
    satMath75: 800,
    satVerbal25: 740,
    satVerbal75: 790,
    actComposite25: 35,
    actComposite75: 36,
  },
  athletics: {
    ncaaDivision: '3',
    ncaaConference: 'NEWMAC',
  },
  climate: {
    koppenClimate: 'D',
    koppenTemperature: 'fa',
    koppenPrecipitation: null,
  },
  culture: {
    partisanDirection: 'D',
    partisanScore: 35.2,
    religiousAffiliation: null,
  },
  demographics: {
    totalEnrollment: 11574,
    percentMale: 0.54,
    percentFemale: 0.46,
    hbcu: false,
    hsi: false,
    aanapisi: false,
    pbi: false,
  },
  meta: {
    schoolUrl: 'www.mit.edu',
    accreditor: 'New England Commission of Higher Education',
  },
  locationDetails: {
    locale: '11',
    region: '1',
    metroArea: 'Boston-Cambridge-Newton',
    metroDistance: 2.5,
  },
}

function renderDetail(props: Partial<Parameters<typeof InstitutionDetail>[0]> = {}) {
  return render(
    <MantineProvider>
      <InstitutionDetail
        institution={MOCK_INSTITUTION}
        opened={true}
        onClose={vi.fn()}
        {...props}
      />
    </MantineProvider>,
  )
}

describe('InstitutionDetail', () => {
  beforeEach(() => {
    mockUseQuery.mockReset()
    // Default mock for SimilarInstitutions
    mockUseQuery.mockReturnValue([{ fetching: false, data: undefined, error: undefined }, vi.fn()])
  })

  it('renders institution name and location', () => {
    renderDetail()
    expect(screen.getAllByText('MIT').length).toBeGreaterThanOrEqual(1)
    expect(screen.getByText('Cambridge, MA')).toBeInTheDocument()
  })

  it('renders core academic fields', () => {
    renderDetail()
    expect(screen.getByText('Private nonprofit')).toBeInTheDocument()
    expect(screen.getByText('Doctorate')).toBeInTheDocument()
    expect(screen.getByText('3:1')).toBeInTheDocument()
    expect(screen.getByText('92.0%')).toBeInTheDocument() // Full-Time Faculty
    expect(screen.getByText('Coeducational')).toBeInTheDocument()
  })

  it('renders cost fields', () => {
    renderDetail()
    // In-state and out-of-state are both $57,590
    expect(screen.getAllByText('$57,590').length).toBe(2)
    expect(screen.getByText('$21,642')).toBeInTheDocument()
    expect(screen.getByText('$17,810')).toBeInTheDocument()
  })

  it('renders admissions fields', () => {
    renderDetail()
    expect(screen.getByText('4.0%')).toBeInTheDocument() // Acceptance rate
    expect(screen.getByText('780–800')).toBeInTheDocument() // SAT Math
    expect(screen.getByText('740–790')).toBeInTheDocument() // SAT Verbal
    expect(screen.getByText('35–36')).toBeInTheDocument() // ACT
    expect(screen.getByText('Common App, Coalition')).toBeInTheDocument()
  })

  it('renders outcomes fields', () => {
    renderDetail()
    expect(screen.getByText('94.0%')).toBeInTheDocument() // Graduation
    expect(screen.getByText('99.0%')).toBeInTheDocument() // Retention
    expect(screen.getByText('1.0%')).toBeInTheDocument() // Transfer
  })

  it('renders rankings with non-null values', () => {
    renderDetail()
    // US News National = 1, Forbes = 3, Niche = 2
    const dialog = screen.getByRole('dialog')
    expect(dialog).toHaveTextContent('US News National')
    expect(dialog).toHaveTextContent('Forbes')
    expect(dialog).toHaveTextContent('Niche')
  })

  it('renders athletics section', () => {
    renderDetail()
    expect(screen.getByText('Division III')).toBeInTheDocument()
    expect(screen.getByText('NEWMAC')).toBeInTheDocument()
  })

  it('renders demographics section', () => {
    renderDetail()
    expect(screen.getByText('11,574')).toBeInTheDocument()
    expect(screen.getByText('54.0%')).toBeInTheDocument() // Male
    expect(screen.getByText('46.0%')).toBeInTheDocument() // Female
  })

  it('does not render minority-serving badges when all false', () => {
    renderDetail()
    expect(screen.queryByText('HBCU')).not.toBeInTheDocument()
    expect(screen.queryByText('HSI')).not.toBeInTheDocument()
  })

  it('renders minority-serving badges when applicable', () => {
    const hbcuInst = {
      ...MOCK_INSTITUTION,
      demographics: { ...MOCK_INSTITUTION.demographics!, hbcu: true, hsi: true },
    }
    renderDetail({ institution: hbcuInst })
    expect(screen.getByText('HBCU')).toBeInTheDocument()
    expect(screen.getByText('HSI')).toBeInTheDocument()
  })

  it('renders cultural environment section', () => {
    renderDetail()
    expect(screen.getByText('Democrat +35.2')).toBeInTheDocument()
  })

  it('renders weather section', () => {
    renderDetail()
    expect(screen.getByText('Continental')).toBeInTheDocument()
  })

  it('renders location details', () => {
    renderDetail()
    expect(screen.getByText('City: Large')).toBeInTheDocument()
    expect(screen.getByText('New England')).toBeInTheDocument()
    expect(screen.getByText('Boston-Cambridge-Newton')).toBeInTheDocument()
  })

  it('renders metadata with school URL as link', () => {
    renderDetail()
    const link = screen.getByText('www.mit.edu')
    expect(link.closest('a')).toHaveAttribute('href', 'https://www.mit.edu')
    expect(screen.getByText('New England Commission of Higher Education')).toBeInTheDocument()
  })

  it('shows "Institution not found" when institution is null', () => {
    renderDetail({ institution: null })
    expect(screen.getByText(/institution not found/i)).toBeInTheDocument()
  })

  it('hides sections when data objects are null', () => {
    const sparseInst: SearchInstitution = {
      unitID: '100000',
      name: 'Sparse U',
      city: 'Nowhere',
      state: 'XX',
    }
    renderDetail({ institution: sparseInst })
    expect(screen.getAllByText('Sparse U').length).toBeGreaterThanOrEqual(1)
    // No athletics, rankings, etc.
    expect(screen.queryByText('Athletics')).not.toBeInTheDocument()
    expect(screen.queryByText('Rankings')).not.toBeInTheDocument()
  })
})

